#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <algorithm>

bool isWord(const std::string& word, const std::string& target) {
    // Remove punctuation from the target word for case-insensitive comparison
    std::string clean_target;
    std::remove_copy_if(target.begin(), target.end(), std::back_inserter(clean_target),
                        [](char ch) { return!std::isalnum(ch); });

    return (clean_target == clean_word);
}

int main() {
    std::string filename;
    std::string word;

    // Prompt user for filename and target word
    std::cout << "Enter the name of the text file: ";
    std::cin >> filename;

    std::cout << "Enter the target word to count: ";
    std::cin >> word;

    // Open the file
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file: " << filename << std::endl;
        return 1;
    }

    // Initialize counter
    int count = 0;

    std::string line;
    while (std::getline(file, line)) {
        std::istringstream iss(line);
        std::string word;
        while (iss >> word) {
            if (isWord(word, word)) {
                count++;
            }
        }
    }

    // Close the file
    file.close();

    // Output the result
    std::cout << "The word '" << word << "' appeared " << count << " times in the file." << std::endl;

    return 0;
}

